import { jsx, jsxs } from 'react/jsx-runtime';
import { Typography } from '../../../Typography/Typography.js';
import { classNames } from '../../../../helpers/classnames.js';
import { forwardRef, useMemo } from 'react';

const PopoverHelperContent = forwardRef(({ title, body, className }, ref) => {
    const titleValue = useMemo(() => {
        if (!title) {
            return null;
        }
        return typeof title === 'string' ? (jsx(Typography, { className: "dsb_helper-title", variant: "h5", children: title })) : (jsx("div", { className: "dsb_helper-title", children: title }));
    }, [title]);
    const bodyValue = useMemo(() => typeof body === 'string' ? (jsx(Typography, { className: "dsb_helper-body", variant: "caption", children: body })) : (jsx("div", { className: "dsb_helper-body", children: body })), [body]);
    return (jsxs("div", { ref: ref, className: classNames('dsb_helper', className), children: [titleValue, bodyValue] }));
});

export { PopoverHelperContent };
